      expect(repayRes.status).to.eq(200);
      expect(repayRes.body.response_code).to.eq(0);
      const repayOrderId = repayRes.body.data.order_no;
      // Confirm Repayment
      const confirmBody = {
        order_id: repayOrderId,
        invoice_no: repayOrderId,
        payment_amount: repaymentAmount,
        payment_date: paymentDate,
        payment_channel: "ThaiQR"
      };
      api.setReqMethod('POST').setReqEndpoint(`https://uat-lms-portal.lendocraft.com/api/repayment/term-loan/test-confirm`).setReqHeadersWithAuth('en_US', makerToken).setReqBody(confirmBody).sendRequest(`confirmRepay_${index}`);
