    // // cf_principal_balance
    // expect(parseFloat(row.cf_principal_balance)).to.be.closeTo(expected.cf_pricipal_balance, 0.01,
    //   `Period ${expected.Period}: cf_principal_balance mismatch`);
    // display_interest_until_due_date
    expect(parseFloat(row.display_interest_until_due_date)).to.be.closeTo(expected.display_interst, 0.01, `Period ${expected.Period}: display_interest mismatch`);
    // display_principal_until_due_date
    expect(parseFloat(row.display_principal_until_due_date)).to.be.closeTo(expected.display_principal, 0.01, `Period ${expected.Period}: display_principal mismatch`);
